$ErrorActionPreference = 'Stop'

$scriptPath = $MyInvocation.MyCommand.Path
if (-not $scriptPath) {
    $scriptPath = Join-Path (Get-Location) 'tools\generate-articles.ps1'
}

$root = Split-Path -Parent (Split-Path -Parent $scriptPath)
$articlesDir = Join-Path $root 'articles'

$articles = @(
    [ordered]@{ Slug = 'promyshlennaya-avtomatizatsiya-chto-vhodit'; Title = 'Что входит в промышленную автоматизацию предприятия'; SeoTitle = 'Что входит в промышленную автоматизацию предприятия'; Description = 'Инженерный разбор состава промышленной автоматизации: шкафы, контроллеры, датчики, диспетчеризация, пусконаладка и типовые задачи на объекте.'; Short = 'Разбор состава систем промышленной автоматизации: от полевого уровня и шкафов управления до диспетчеризации и ввода в работу.'; Focus = 'состав промышленной автоматизации'; ObjectFocus = 'промышленных предприятий, котельных, насосных станций и очистных сооружений'; RegionNote = 'Для ЮФО особенно характерны проекты, где автоматизация внедряется поэтапно в Ростове-на-Дону, Краснодаре, Ставрополе, Волгограде и Астрахани.' },
    [ordered]@{ Slug = 'etapy-vnedreniya-avtomatizatsii'; Title = 'Этапы внедрения промышленной автоматизации на объекте'; SeoTitle = 'Этапы внедрения промышленной автоматизации'; Description = 'Какие этапы проходит внедрение промышленной автоматизации: обследование, проект, монтаж, КИПиА, наладка, запуск и сдача объекта.'; Short = 'Пошаговая инженерная схема внедрения автоматизации: от обследования и анализа документации до запуска и исполнительной документации.'; Focus = 'этапы внедрения автоматизации'; ObjectFocus = 'генподрядных и субподрядных проектов на инженерных и производственных площадках'; RegionNote = 'На объектах ЮФО сроки и логистика часто зависят от стадии стройготовности, поэтому этапность особенно важна.' },
    [ordered]@{ Slug = 'avtomatizatsiya-vs-dispetcherizatsiya'; Title = 'Чем отличается автоматизация технологических процессов от диспетчеризации'; SeoTitle = 'Автоматизация и диспетчеризация: в чем разница'; Description = 'Инженерное различие между автоматизацией и диспетчеризацией: уровни управления, оборудование, сигналы, задачи эксплуатации и типовые ошибки.'; Short = 'Сравнение автоматизации и диспетчеризации без маркетинговых упрощений: уровни систем, оборудование, сигналы и практические задачи.'; Focus = 'разница между автоматизацией и диспетчеризацией'; ObjectFocus = 'котельных, очистных сооружений, тепличных комплексов и распределенных инженерных систем'; RegionNote = 'Для распределенных объектов ЮФО диспетчеризация часто критична не меньше локальной автоматики.' },
    [ordered]@{ Slug = 'modernizatsiya-avtomatizatsii'; Title = 'Когда автоматизацию выгоднее модернизировать, а не строить заново'; SeoTitle = 'Когда модернизировать автоматизацию выгоднее'; Description = 'Когда модернизация автоматизации оправдана инженерно и экономически: оценка шкафов, датчиков, кабелей, логики и рисков полного демонтажа.'; Short = 'Критерии, по которым определяют: модернизировать существующую автоматику или строить новую систему с нуля.'; Focus = 'модернизация существующих систем автоматизации'; ObjectFocus = 'действующих промышленных предприятий и инженерных объектов с ограничениями по остановке'; RegionNote = 'В ЮФО много объектов реконструкции, где модернизация позволяет сократить простой и объем демонтажа.' },
    [ordered]@{ Slug = 'montazh-kipia'; Title = 'Что входит в монтаж КИПиА на промышленном объекте'; SeoTitle = 'Что входит в монтаж КИПиА на объекте'; Description = 'Подробно о составе работ по монтажу КИПиА: приборы, кабели, импульсные линии, шкафы, маркировка, проверка сигналов и подготовка к ПНР.'; Short = 'Состав и логика работ по монтажу КИПиА на промышленных и инженерных объектах.'; Focus = 'монтаж КИПиА'; ObjectFocus = 'котельных, насосных станций, очистных сооружений и производственных линий'; RegionNote = 'Для объектов ЮФО особенно важны аккуратная трассировка, полевые условия и устойчивость приборного контура.' },
    [ordered]@{ Slug = 'oshibki-montazha-kipia'; Title = 'Типовые ошибки при монтаже КИПиА'; SeoTitle = 'Типовые ошибки при монтаже КИПиА'; Description = 'Инженерный обзор частых ошибок при монтаже КИПиА: неверные подключения, трассировка, маркировка, приборные линии, экранирование и подготовка к запуску.'; Short = 'Разбор ошибок, которые чаще всего приводят к нестабильным сигналам, авариям и затяжной пусконаладке КИПиА.'; Focus = 'ошибки монтажа КИПиА'; ObjectFocus = 'производственных и инженерных систем с высокой долей полевых сигналов'; RegionNote = 'На объектах ЮФО такие ошибки часто выявляются уже на стадии запуска, когда переделка особенно дорога.' },
