    [ordered]@{ Slug = 'puskonaladka-kipia'; Title = 'Пусконаладка КИПиА на промышленном объекте'; SeoTitle = 'Пусконаладка КИПиА на промышленном объекте'; Description = 'Что включает пусконаладка КИПиА: проверка цепей, калибровка сигналов, логика защит, настройка шкафов и подготовка системы к эксплуатации.'; Short = 'Инженерный порядок пусконаладки КИПиА: от проверки цепей и приборов до вывода объекта в рабочий режим.'; Focus = 'пусконаладка КИПиА'; ObjectFocus = 'объектов, где приборный контур напрямую влияет на алгоритмы автоматики'; RegionNote = 'Для объектов ЮФО ПНР часто выполняется в сжатые сроки и в связке с поэтапным вводом инженерных систем.' },
    [ordered]@{ Slug = 'avtomatizatsiya-kotelnyh'; Title = 'Автоматизация котельных: основные системы'; SeoTitle = 'Автоматизация котельных: основные системы'; Description = 'Какие системы входят в автоматизацию котельной: котлы, насосы, защиты, КИПиА, диспетчеризация, силовая часть и требования к запуску.'; Short = 'Структурный разбор автоматизации котельных: основные подсистемы, оборудование, риски и инженерные требования.'; Focus = 'автоматизация котельных'; ObjectFocus = 'блочно-модульных и стационарных котельных, тепловых пунктов и коммунальных объектов'; RegionNote = 'В ЮФО автоматизация котельных востребована на муниципальных, производственных и аграрных объектах.' },
