    [ordered]@{ Slug = 'avtomatizatsiya-teplichnyh-kompleksov'; Title = 'Автоматизация тепличных комплексов'; SeoTitle = 'Автоматизация тепличных комплексов'; Description = 'Что входит в автоматизацию тепличных комплексов: микроклимат, полив, вентиляция, отопление, электромонтаж, датчики и диспетчеризация.'; Short = 'Инженерный разбор автоматизации тепличных комплексов и связанных инженерных систем.'; Focus = 'автоматизация тепличных комплексов'; ObjectFocus = 'тепличных комплексов, агрохолдингов и объектов с выраженным контуром микроклимата'; RegionNote = 'Для Краснодарского края и других аграрных регионов ЮФО эта тема особенно релевантна.' },
    [ordered]@{ Slug = 'avtomatizatsiya-nasosnyh-stanciy'; Title = 'Автоматизация насосных станций'; SeoTitle = 'Автоматизация насосных станций'; Description = 'Инженерный обзор автоматизации насосных станций: управление насосами, уровни, частотные преобразователи, КИПиА, аварии и диспетчеризация.'; Short = 'Состав систем автоматизации насосных станций и типовые инженерные задачи на объектах водоснабжения и перекачки.'; Focus = 'автоматизация насосных станций'; ObjectFocus = 'насосных станций, КНС, систем водоснабжения и водоотведения'; RegionNote = 'Для Волгограда, Астрахани и Ставрополья особенно важны надежность насосных алгоритмов и удаленный контроль.' },
    [ordered]@{ Slug = 'pochemu-ne-zapuskaetsya-avtomatika'; Title = 'Почему не запускается автоматизация после монтажа'; SeoTitle = 'Почему не запускается автоматизация после монтажа'; Description = 'Почему система автоматизации не запускается после монтажа: типовые причины по силовой части, КИПиА, сигналам, шкафам и пусконаладке.'; Short = 'Практический разбор причин, из-за которых автоматика не выходит в рабочий режим после завершения монтажа.'; Focus = 'причины отказа запуска автоматики'; ObjectFocus = 'объектов, где монтаж завершен, но система не проходит комплексный пуск'; RegionNote = 'Такие ситуации часто возникают на объектах ЮФО при сжатых сроках и нестыковках между разделами.' },
