$articleProfiles = @{
    'promyshlennaya-avtomatizatsiya-chto-vhodit' = [ordered]@{
        HeroLead                 = 'Материал нужен тем, кто должен понять состав промышленной автоматизации не по рекламному перечню, а по реальному набору инженерных подсистем: от полевого уровня и шкафов до диспетчеризации, архивов и комплексной пусконаладки.'
        HeroSupport              = 'На практике главный вопрос звучит не как "что входит", а как "какие элементы действительно необходимы именно для этого объекта". Для насосной станции, котельной и производственной линии ответ будет разным, потому что различаются требования к защитам, резервированию, телеметрии и режимам работы оборудования.'
        PracticeTitle            = 'Из каких контуров реально складывается система'
        PracticeParagraph        = 'Если смотреть инженерно, промышленная автоматизация складывается из шести контуров: измерение параметров, логика управления, силовое воздействие на оборудование, аварийные блокировки, операторский интерфейс и передача данных на верхний уровень. Ошибка начинается тогда, когда заказчик или подрядчик воспринимает один из контуров как необязательный и переносит решение на позднюю стадию.'
        SystemsTitle             = 'Какие компоненты влияют на результат сильнее всего'
        SystemsParagraph         = 'На большинстве объектов ключевую роль играют не сами контроллеры, а качество полевого контура и понятная архитектура шкафов. Нестабильный датчик уровня, неразмеченные клеммы или неувязанный интерфейс обмена способны обнулить пользу даже от хорошей ПЛК-программы.'
        ProblemsTitle            = 'Где чаще всего занижают объем работ'
        ProblemsParagraph        = 'Чаще всего недооценивают перечни сигналов, шкафную компоновку, необходимость локального ручного режима и объем пусконаладочных проверок. Из-за этого смета выглядит компактной только на бумаге, а на площадке появляются дополнительные цепи, доработки по месту и спор о том, кто должен закрыть инженерные пробелы.'
