function Escape-Html([string]$value) {
    return $value.Replace('&', '&amp;').Replace('<', '&lt;').Replace('>', '&gt;').Replace('"', '&quot;')
}

function Build-ParagraphMarkup([string]$text, [string]$indent) {
    return "$indent<p>$text</p>"
}

function Build-ChecklistMarkup([array]$items, [string]$indent) {
    $lines = foreach ($item in $items) {
        "$indent<li>$item</li>"
    }
    return ($lines -join "`n")
}

function Build-OtherArticles([hashtable]$article, [array]$allArticles, [hashtable]$profile) {
    if ($profile.RelatedSlugs) {
        $others = foreach ($slug in $profile.RelatedSlugs) {
            $allArticles | Where-Object { $_.Slug -eq $slug } | Select-Object -First 1
        }
    }
    else {
        $others = $allArticles | Where-Object { $_.Slug -ne $article.Slug } | Select-Object -First 3
    }
    $items = foreach ($item in $others) {
        if ($null -ne $item) {
            "                        <li><a href=`"$($item.Slug).html`">$($item.Title)</a></li>"
        }
    }
    return ($items -join "`n")
}

