foreach ($article in $articles) {
    $articlePath = Join-Path $articlesDir ($article.Slug + '.html')
    Set-Content -Path $articlePath -Value (Build-ArticleHtml $article $articles) -Encoding UTF8
}

$indexPath = Join-Path $articlesDir 'index.html'
Set-Content -Path $indexPath -Value (Build-IndexHtml $articles) -Encoding UTF8
